/**
 * This interface was referenced by `Config`'s JSON-Schema
 * via the `definition` "header".
 */
export interface Header {
  id: string;
  /**
   * The banner shown at the very top of the site. Use it to highlight promotions, events, or important messages.
   */
  announcementBar: {
    /**
     * Toggle the announcement bar on or off site-wide.
     */
    enabled?: boolean | null;
    /**
     * The message displayed in the announcement bar (e.g. "New workshops available!").
     */
    text: string;
    /**
     * URL the announcement links to (e.g. "/workshops"). Leave empty for no link.
     */
    link?: string | null;
  };
  /**
   * The main navigation links shown in the header. Drag to reorder. Each item can optionally have a dropdown with sub-items.
   */
  navItems?:
    | {
        link: {
          type?: ('reference' | 'custom') | null;
          newTab?: boolean | null;
          reference?: {
            relationTo: 'pages';
            value: string | Page;
          } | null;
          url?: string | null;
          label: string;
        };
        /**
         * Optional sub-items shown in a dropdown menu. If empty, the nav item renders as a simple link.
         */
        dropdownItems?:
          | {
              label: string;
              href: string;
              /**
               * Short description shown below the label in the dropdown.
               */
              description?: string | null;
              /**
               * Check to render this item with smaller font size (for workshop types).
               */
              isSmall?: boolean | null;
              /**
               * Show the label in the menu but prevent navigation — e.g. "coming soon" items.
               */
              disabled?: boolean | null;
              id?: string | null;
            }[]
          | null;
        id?: string | null;
      }[]
    | null;
  updatedAt?: string | null;
  createdAt?: string | null;
}
